import { useState, useEffect } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";

// --- Mock Data (Essential for calculation) ---
const mockItems = Array.from({ length: 50 }, (_, i) => ({ id: i + 1, name: `Item ${i + 1}` }));
const itemsPerPage = 12;

// --- Pagination Component Focused on Logic ---
export default function PaginationLogic({ listName = 'default' }) {
  const itemToShow = mockItems;

  // 1. State and Persistence Logic: Reads from sessionStorage on load
  const [currentPage, setCurrentPage] = useState(() => {
    if (typeof window !== 'undefined') {
      const storageKey = `itemSectionPage_${listName}`;
      const savedPage = sessionStorage.getItem(storageKey);
      return savedPage ? parseInt(savedPage, 10) : 1;
    }
    return 1;
  });

  // Effect to save currentPage to sessionStorage whenever it changes
  useEffect(() => {
    if (typeof window !== 'undefined') {
      const storageKey = `itemSectionPage_${listName}`;
      sessionStorage.setItem(storageKey, currentPage.toString());
    }
  }, [currentPage, listName]);

  // 2. Pagination Calculations
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = itemToShow.slice(indexOfFirstItem, indexOfLastItem);
  const totalPages = Math.ceil(itemToShow.length / itemsPerPage);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);

  // 3. Logic for visible page numbers (Max 5 pages visible)
  const maxPagesToShow = 5;
  let startPage = Math.max(1, currentPage - Math.floor(maxPagesToShow / 2));
  let endPage = Math.min(totalPages, startPage + maxPagesToShow - 1);

  if (endPage - startPage + 1 < maxPagesToShow) {
    startPage = Math.max(1, endPage - maxPagesToShow + 1);
  }

  const pageNumbers = [];
  for (let i = startPage; i <= endPage; i++) {
    pageNumbers.push(i);
  }

  return (
    <div className="p-8">
      <h3 className="text-xl font-semibold mb-4 text-indigo-700">Displaying Items {indexOfFirstItem + 1} - {Math.min(indexOfLastItem, itemToShow.length)} of {itemToShow.length}</h3>
      
      {/* ITEMS DISPLAY AREA (Simplified) */}
      <div className="grid grid-cols-4 gap-4 mb-8">
        {currentItems.map((item) => (
          <div key={item.id} className="p-3 bg-gray-100 rounded-lg text-sm truncate">{item.name}</div>
        ))}
      </div>

      {/* 4. PAGINATION BUTTONS JSX */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-1 py-6">
          
          {/* Previous Button */}
          <button
            onClick={() => paginate(currentPage - 1)}
            className="p-3 text-sm text-gray-700 rounded-lg hover:bg-gray-200 transition duration-150 disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
            disabled={currentPage === 1}
          >
            <ChevronLeft className="w-4 h-4" />
            <span className="hidden sm:inline">Prev</span>
          </button>

          {/* Individual Page Number Buttons */}
          {pageNumbers.map((number) => (
            <button
              key={number}
              onClick={() => paginate(number)}
              className={`
                px-4 py-2 text-sm font-semibold rounded-lg transition duration-150
                ${currentPage === number
                  ? 'bg-blue-600 text-white shadow-lg'
                  : 'bg-white text-gray-700 hover:bg-gray-100 border border-gray-300'
                }
              `}
            >
              {number}
            </button>
          ))}
          
          {/* Ellipsis and Last Page */}
          {endPage < totalPages && (
            <>
              <span className="px-2 py-2 text-gray-500">...</span>
              <button
                onClick={() => paginate(totalPages)}
                className="px-4 py-2 text-sm font-semibold rounded-lg bg-white text-gray-700 hover:bg-gray-100 border border-gray-300 transition duration-150"
              >
                {totalPages}
              </button>
            </>
          )}

          {/* Next Button */}
          <button
            onClick={() => paginate(currentPage + 1)}
            className="p-3 text-sm text-gray-700 rounded-lg hover:bg-gray-200 transition duration-150 disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
            disabled={currentPage === totalPages}
          >
            <span className="hidden sm:inline">Next</span>
            <ChevronRight className="w-4 h-4" />
          </button>
        </div>
      )}
    </div>
  );
}